head.script:
//==================================================================================================================
// id       : ar_104_01_01b
// 이름     : Master Air Waybill (Export)
// 경로     : 해외물류
// 작 성 자 : 김용호
// 작 업 일 : 2026-01-19
// 사용계정 : 내부
// 비고     :
//
// 업로드   :
// 다운로드 : 
// 레포트   :
// 호출     : 
//==================================================================================================================

scwin.userId = "";
scwin.airexgbim = "";
scwin.cvsslMgntNo = "";
scwin.empNo = "";
scwin.lobranCd = "";
scwin.p_blno = "";
scwin.p_clntNm = "";
scwin.p_clntNo = "";
scwin.p_kcomcd = "";
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";
scwin.p_type = "";
scwin.hd_kcomcd = "DBEX";
scwin.hd_iogb = "O";
scwin.hd_otpc = "";
scwin.hd_shipgb = "";
scwin.hd_endgb = "";
scwin.hd_hodrNo = "";


//--------------------------------------------------------------------------//
//							메세지 상수 선언									//
//--------------------------------------------------------------------------//
scwin.MSG_LO_WRN_001 = "%1 에 등록 되어 있어 삭제 불가능 합니다.";
scwin.MSG_LO_WRN_002 = "잘못된 Master Number 입니다";
scwin.MSG_LO_WRN_003 = "%1 자료를 생성하세요";
scwin.MSG_LO_WRN_004 = "해당 B/L 번호로 복사 하시겠습니까?";
scwin.MSG_LO_WRN_005 = "이미 인보이스  발행 되어 삭제 불가능 합니다.";
scwin.MSG_LO_WRN_010 = "1GG 부서 코드는 사용하실 수 없습니다. ";

//--------------------------------------------------------------------------//
scwin.processFlag = "";  // 처리 결과를 체크하는 Flag
scwin.actionFlag = "";

//전역변수-페이지 링크로 들어 왔을때 해당 b/l, CONSOL 번호  조회 여부 체크
scwin.linkType = "New";
scwin.spRtn = "";  //인보이스 체크 결과
scwin.spMsg = "";  //인보이스 체크 메세지
scwin.freightYn = ""; //b/l 조회시 운임 발행 여부 값
scwin.empNo = "";
scwin.txt_shnm1 = "";
scwin.txt_shnm2 = "";
scwin.txt_shnm3 = "";
scwin.txt_shnm4 = "";
scwin.txt_shnm5 = "";
scwin.txt_cnnm1 = "";
scwin.txt_cnnm2 = "";
scwin.txt_cnnm3 = "";
scwin.txt_cnnm4 = "";
scwin.txt_cnnm5 = "";
scwin.txt_ntnm1 = "";
scwin.txt_ntnm2 = "";
scwin.txt_ntnm3 = "";
scwin.txt_ntnm4 = "";
scwin.txt_ntnm5 = "";
//-------------------------------------------------------------------------
// 화면로딩시
//-------------------------------------------------------------------------
scwin.onpageload = async function () {
    scwin.memJson = $c.data.getMemInfo();

	scwin.userId = $c.data.getMemInfo("userId") || "";
	scwin.p_lobranCd = $c.data.getMemInfo("lobranCd") || " ";
	scwin.p_lobranNm = $c.data.getMemInfo("lobranNm") || "";
	scwin.empNo = $c.data.getMemInfo("userId") || "";

    scwin.cvsslMgntNo = $c.data.getParameter("cvsslMgntNo") || "";
	scwin.p_kcomcd = $c.data.getParameter("kcomcd") || "";
	scwin.p_blno = $c.data.getParameter("blno") || "";
	scwin.p_type = $c.data.getParameter("type") || "";

	scwin.p_clntNo = $c.data.getMemInfo("clntNo") || "";
	scwin.p_clntNm = $c.data.getMemInfo("clntNm") || "";
	scwin.airexgbim = $c.data.getMemInfo("airexgbim") || "";
	scwin.hd_kcomcd = scwin.p_kcomcd || "DBEX";
	scwin.hd_iogb = "O";
	scwin.hd_otpc = "";
	scwin.hd_shipgb = "";
	scwin.hd_endgb = "";
	scwin.hd_hodrNo = "";

    const codeOptions = [
        { grpCd: "IL005", compID: "lc_inco"},
    ];
    $c.data.setCommonCode(codeOptions, function() {
        lc_inco.setSelectedIndex(-1);
    });

	if (scwin.f_OnLoad) { await scwin.f_OnLoad(); }
};

scwin.f_OnLoad = async function () {
	scwin.f_initSetTab();
};

scwin.onUdcCompleted = async function() {
    scwin.f_Set("INIT");

	await scwin.f_ds_hdif();
	scwin.processFlag = "None";
	await scwin.f_getParametrSetting(); // link처리, 조회

	ed_blno.focus();

	$c.gus.cfDisableObjects([txt_updid]);
	$c.gus.cfDisableObjects([txt_upddt]);
};

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = async function () {
	var kcomcd = scwin.p_kcomcd || scwin.hd_kcomcd;
	var blno = scwin.p_blno;
	var type = scwin.p_type;

	if (blno == 'null' || blno == '') {
		return false;
	}

	scwin.hd_kcomcd = kcomcd;
	ed_blno.setValue(blno);

	scwin.linkType = type;

	scwin.f_MhnoLoading();
	await scwin.f_Retrieve();

	if (scwin.linkType == "MawbCreate") {
		scwin.f_Create();

		if (scwin.actionFlag == "Create") {
			if (ed_blno.getValue() == "") {
				await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master Number"]);  // 필수 입력 항목 입니다.
				return false;
			}
			//생성시 입력한 Bill 번호를 Booking 정보에서 유무 확인
			scwin.f_ProcessBinding(dma_MasterBillSearch, "MasterBillSearch");
			await $c.sbm.execute(sbm_RetrieveBookingList);
		}
	}
}

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function (gubun) {
	switch (gubun) {
		case "Create":
			//default 동부국제물류
			ed_shcd.setValue(scwin.p_clntNo);

			if (ed_shcd.getValue() != "") {
				scwin.f_PopUp("Shipper", "T", "F", "F");
			}

			txa_mark.setValue("NO MARK");
			ed_dvcr.setValue("N.V.D");
			ed_insu.setValue("NIL");
			ed_acif1.setValue("FREIGHT PREPAID");
			ed_cucd.setValue("KRW");
			rd_frpc.setValue("PP");
			chb_otpc1.setValue("1");
			chb_otpc2.setValue("0");
			lc_mmhno.setValue("");
			ed_blno.focus();

			ta_hhs.setValue("");
			ta_hhc.setValue("");
			ta_hhn.setValue("");

            //추가
            ed_mftpkg.setValue("0");
            ed_mftwht.setValue("0");
            ed_tcwht.setValue("0");

			break;

		case "Copy":
			ed_blno.setValue("");
			lc_mmhno.setValue("");
			ed_srno.setValue("");

			break;

        default:
			break;
	}
};


//---------------------------------------------------------
// Tab 초기화
//---------------------------------------------------------
scwin.f_initSetTab = function () {
	//$c.gus.cfEnableObjects([tr_tab_center0, tr_tab_center1]);
	scwin.f_selectTabMenu(0);
};

//-------------------------------------------------------------------------
// Retrieve
//-------------------------------------------------------------------------
scwin.f_Retrieve = async function () {
	if (ed_blno.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master B/L No"]);
		ed_blno.focus();
		return false;
	}

    ds_MasterBillInfo.removeAll();
	ds_HouseBillInfo.removeAll();
    totalRow.setValue(ds_HouseBillInfo.getTotalRow());

	scwin.f_ProcessBinding(dma_MasterBillSearch, "MasterBillSearch");
	let e = await $c.sbm.execute(sbm_Retrieve);
    // if (e.responseJSON.resultDataSet[0].Code < 0) {
    //     return
    // } else {
    //     await scwin.sbm_Retrieve_submitdone();
    // }
};


//-------------------------------------------------------------------------
// House b/l 바로 가기
//-------------------------------------------------------------------------
scwin.f_HouseLink = async function () {
	var row = ds_HouseBillInfo.getRowPosition();

    if (row >= 0) {

        var v_blno = ds_HouseBillInfo.getCellData(row, "blno");

        scwin._openMenu(
            "Export House B/L",
            "/ui/il/airout/aobl/ar_104_01_01b.xml",
            "ar_104_01_01b.xml",
            { kcomcd: scwin.hd_kcomcd, blno: v_blno }
        );

    } else {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_056);
		return;
	}
}
//-------------------------------------------------------------------------
//조회 결과
//-------------------------------------------------------------------------
scwin.f_ProcessResult = async function (gubun) {
	switch (gubun) {
		case "None":
			if (scwin.linkType != "MawbCreate") { // 마스터 부킹에서 넘어와 마스터 조회 시 없으면 그 type none로 변경해서 create시켜 주기 위해
				scwin.f_Set("INIT");
				await $c.gus.cfAlertMsg(E_MSG_CM_ERR_003);  // 해당 되는 자료가 없습니다.
				ed_blno.focus();
			}
			break;

		case "MasterInfo":
			if (scwin.linkType == "MawbCreate") { // 마스터 부킹에서 넘어와 마스터 조회 시 없으면 그 type none로 변경해서 create시켜 주기 위해
				scwin.linkType = "None";
			}
			scwin.f_OtherTypeGetting();
			scwin.f_TypeInfoSetting("MasterInfo", ds_MasterBillInfo);
			scwin.f_Set("RETRIEVE");

			await scwin.f_InvoiceCheck_All("B"); //운임 발생시 ITEM , Department 수정 못 하게 하기 위해 검색

			ed_blno.focus();
			break;

		case "NotExistBookingInfo":
			await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_003, ["Master Booking"]);  // @ 자료를 생성하세요
			scwin.processFlag = "None";
			ed_srno.setValue("");
			break;

		case "ExistBookingInfo":
			scwin.processFlag = "ExistBookingInfo";
			scwin.f_BookingListBinding("Retrieve", ds_MasterBookingInfo, ds_MasterBillInfo);
			scwin.f_TypeInfoSetting("BookingInfo", ds_MasterBookingInfo);

			//lc_mmhno.focus();
			if (ed_shipgb.getValue() == "Direct") {
				$c.gus.cfEnableObjects([ed_srno]);
				ed_shcd.focus();
			} else {
				$c.gus.cfDisableObjects([ed_srno]);
				ed_shcd.focus();
			}
			break;

		default:
			break;
	}
}

//-------------------------------------------------------------------------
//Invoice Chedk
//-------------------------------------------------------------------------
scwin.f_InvoiceCheck_All = async function (gbun) {
	var ds = dma_InvoiceCheckParam;

	ds.undo();

    ds_MasterBillInfo.setRowPosition(0);

	ds.set("odrNo", ds_MasterBillInfo.getCellData(ds_MasterBillInfo.getRowPosition(), "odrNo"));	// Order No
	ds.set("mblHblCls", "M");
	ds.set("kcomcd", scwin.hd_kcomcd);	// 법인코드
	ds.set("seaAirCls", "A");	// 해운/항공 구분
	ds.set("blNo", ed_blno.getValue());	// Master Bill No
	ds.set("mhno", lc_mmhno.getValue());	// Consol No
	if (gbun == "B") {
		ds.set("gbun", 'B'); // b/l 운임 구분 ('B','F')
	} else {
		ds.set("gbun", 'F'); // b/l 운임 구분 ('B','F')
	}

	scwin.spMsg = "";
	scwin.spRtn = "-1";
	let e1 = await $c.sbm.execute(sbm_InvoiceCheck);

    if (e1.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

	scwin.spMsg = ds_InvoiceCheck.getCellData(ds_InvoiceCheck.getRowPosition() || 0, "spMsg");
	scwin.spRtn = ds_InvoiceCheck.getCellData(ds_InvoiceCheck.getRowPosition() || 0, "spRtn");
	scwin.freightYn = scwin.spRtn;

	var shipgb = ds_MasterBillInfo.getCellData(ds_MasterBillInfo.getRowPosition() || 0, "shipgb");

	if (shipgb == "D" && scwin.spRtn == "0") { //Direct house order no 로 한번 더 체크 해줌
		ds.undo();

		ds.set("odrNo", ds_MasterBillInfo.getCellData(ds_MasterBillInfo.getRowPosition() || 0, "hodrNo"));	// Order No
		ds.set("mblHblCls", "H");
		ds.set("kcomcd", scwin.hd_kcomcd);	// 법인코드
		ds.set("seaAirCls", "A");	// 해운/항공 구분
		ds.set("blNo", ed_blno.getValue());	// Master Bill No
		ds.set("mhno", lc_mmhno.getValue());	// Consol No
		if (gbun == "B") {
			ds.set("gbun", 'B'); // b/l 운임 구분 ('B','F')
		} else {
			ds.set("gbun", 'F'); // b/l 운임 구분 ('B','F')
		}

		scwin.spMsg = "";
		scwin.spRtn = "-1";
		let e2 = await $c.sbm.execute(sbm_InvoiceCheck);

        if (e2.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

		scwin.spMsg = ds_InvoiceCheck.getCellData(ds_InvoiceCheck.getRowPosition() || 0, "spMsg");
		scwin.spRtn = ds_InvoiceCheck.getCellData(ds_InvoiceCheck.getRowPosition() || 0, "spRtn");
		scwin.freightYn = scwin.spRtn;
	}

}

//-------------------------------------------------------------------------
//조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = function (ds, gubun) {
	switch (gubun) {
		case "MasterBillSearch":
			ds.set("kcomcd", scwin.hd_kcomcd);
			ds.set("blno", ed_blno.getValue());
			ds.set("mhno", lc_mmhno.getValue());
			ds.set("iogb", scwin.hd_iogb);
			break;

		case "MasterBillSave":
			ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
			ds.setCellData(ds.getRowPosition(), "iogb", scwin.hd_iogb);
			ds.setCellData(ds.getRowPosition(), "blno", ed_blno.getValue());
			break;

		case "CustomerBookingCheck":
			ds.set("kcomcd", scwin.hd_kcomcd);
			ds.set("srno", ed_srno.getValue());
			ds.set("iogb", scwin.hd_iogb);
			break;

		default:
			break;
	}
}

//-------------------------------------------------------------------------
// Create
//-------------------------------------------------------------------------
scwin.f_Create = function () {
	ds_MasterBillInfo.removeAll();
	ds_MasterBillInfo.insertRow(0);
    ds_MasterBillInfo.setRowPosition(0);

	ds_HouseBillInfo.removeAll();
    totalRow.setValue(ds_HouseBillInfo.getTotalRow());

	scwin.f_Set("CREATE");
	scwin.actionFlag = "Create";
	ed_blno.focus();
	txt_ediItem.setValue("CONSOLIDATION");

    scwin._syncHiddenFromDs();
}

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function () {

	if (scwin.actionFlag == "Create") {
		scwin.f_Set("INIT");
		scwin.processFlag = "None";
	} else {
		scwin.f_Set("RETRIEVE");
	};
    lc_inco.setValue("");
	ds_MasterBillInfo.undoAll();
}

//-------------------------------------------------------------------------
// Update
//-------------------------------------------------------------------------
scwin.f_Update = function () {
	scwin.actionFlag = "Update";
	scwin.f_Set("UPDATE");
}

//-------------------------------------------------------------------------
// Save
//-------------------------------------------------------------------------
scwin.f_Save = async function () {

	scwin.f_TextareaSave();
	scwin._syncHiddenToDs();

	//if (scwin.actionFlag == "Create" || scwin.actionFlag == "Copy"){
	if (scwin.actionFlag == "Copy") {
		if (lc_mmhno.getValue() != "") {
			await $c.gus.cfAlertMsg(E_MSG_CM_ERR_032, [ed_blno.getValue()]);  //@은(는) 중복될 수 없습니다.
			ed_blno.focus();
			return false;
		}

        ds_MasterBillInfo.setRowPosition(0);
		ds_MasterBillInfo.setRowStatus(ds_MasterBillInfo.getRowPosition(), "C");  //Gauce jobType : Insert 로 변경
	}

	if (ed_shCtcd.getValue() == "") {
		await $c.win.alert("Shipper Country code is mandatory.");
		return false;
	}

	if (ed_cnCtcd.getValue() == "") {
		await $c.win.alert("Consignee Country code is mandatory.");
		return false;
	}

	if (txt_ediItem.getValue() == "") {
		await $c.win.alert("EDI Item is mandatory.");
		return false;
	}

	scwin.f_ProcessBinding(ds_MasterBillInfo, "MasterBillSave");
	scwin.f_OtherTypeSetting();

	if (ds_MasterBillInfo.getModifiedIndex().length > 0) {
		scwin.f_selectTabMenu(0);  // 저장 전 TAB FOCUS  이동
		if (await scwin.f_ReqFieldChk()) {
			scwin.actionFlag = "Save";
			await $c.sbm.execute(sbm_Save);
		} else {
			await $c.gus.cfAlertMsg(E_MSG_CM_ERR_001, ["Master Info"]);  //@은(는) 변경된 사항이 없습니다.
		}
	}
}

//유효성검사
scwin.f_ReqFieldChk = async function () {
	if (ed_blno.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Master B/L No"]);
		ed_blno.focus();
		return false;
	}
	if (ed_ondt.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Onboard Date"]);
		ed_ondt.focus();
		return false;
	}
	if (ed_avdt.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Arrival Date"]);
		ed_avdt.focus();
		return false;
	}
	if (scwin.hd_shipgb == "D" && ed_srno.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Booking No"]);
		ed_srno.focus();
		return false;
	}
	if (ed_dept.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Department Info"]);
		ed_dept.focus();
		return false;
	}
	if (ed_locd.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Salesman Info"]);
		ed_locd.focus();
		return false;
	}
	if (ed_itcd.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Item Info"]);
		//scwin.f_selectTabMenu(1);
		ed_itcd.focus();
		return false;
	}
	if (ed_cjdt.getValue() == "") {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_002, ["Result Date Date"]);
		ed_cjdt.focus();
		return false;
	}
	if ($c.gus.cfIsAfterDate(ed_ondt.getValue(), ed_avdt.getValue()) == false) {
		await $c.gus.cfAlertMsg(E_MSG_CM_ERR_039);  // 시작일자를 종료일 이전으로 선택[입력]하여 주십시오.
		ed_ondt.focus();
		return false;
	}
	if (ed_dept.getValue() == "1GG") {
		await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_010, ["Department Info"]);
		ed_dept.focus();
		return false;
	}
	if (await $c.gus.cfValidate([ed_blno,lc_mmhno,ed_srno]) == false) {
		return false;
	}

	return true;
}

//-------------------------------------------------------------------------------
//  Copy
//	Master Booking 정보에 존재 유무를 확인
//	유 -> Booking 입력
//	무 -> Booking 정보를 가져 온다. (Bill Type, Carrier, Onboard Date, Arrival Date 등
//	필요한 기초 정보를 가져온다.
//-------------------------------------------------------------------------------
scwin.f_Copy = async function () {
	if (await $c.win.confirm(scwin.MSG_LO_WRN_004)) { 	//해당 B/L 번호로 복사 하시겠습니까?
		scwin.actionFlag = "Copy";
		scwin.f_DefaultValue("Copy");
		scwin.f_Set("CREATE");
        scwin._syncHiddenFromDs();
		ed_blno.focus();
	}
}

//-------------------------------------------------------------------------
// Delete
//-------------------------------------------------------------------------
scwin.f_Delete = async function () {
	if ((ds_HouseBillInfo.getRowCount() > 0) && (scwin.hd_shipgb != "D")) {
		await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_001, ["House Information"]);
		ed_blno.focus();
		return false;
	}

	if (await $c.win.confirm(E_MSG_CM_CRM_004)) {  //삭제하시겠습니까?

		await scwin.f_InvoiceCheck_All("F"); //운임 발행 여부 확인

		if (scwin.spRtn == "0") {
			scwin.actionFlag = "Delete";

            // ds_MasterBillInfo.DeleteMarked();
            var rowIdx = ds_MasterBillInfo.getRowPosition() || 0;

            if (ds_MasterBillInfo.getRowStatus(rowIdx) == "C") {
                ds_MasterBillInfo.removeRow(rowIdx);
            } else {
                ds_MasterBillInfo.deleteRow(rowIdx);
            }

			await $c.sbm.execute(sbm_Save);

		} else {
			await $c.gus.cfAlertMsg(scwin.MSG_LO_WRN_005);
		}
	}
}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
	switch (gubun) {

		case "INIT": //초기화
			$c.gus.cfDisableKeyData();
			$c.gus.cfDisableBtnOnly([btn_Update, btn_Save, btn_Delete, btn_Cancel]);
			$c.gus.cfDisableBtnOnly([btn_Copy, pu_Freight, pu_AmsEdi, pu_PlSheet, pu_Manifest, pu_Dimens, pu_Print, pu_departmentChange]);
			$c.gus.cfEnableBtnOnly([btn_Create, pu_Find, pu_Hawb, pu_Sr]);
			scwin.f_DisablePopUpObj();
			break;

		case "RETRIEVE":  //조회모드
			$c.gus.cfDisableKeyData();
			scwin.f_DisablePopUpObj();
			$c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
			$c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
			$c.gus.cfEnableBtnOnly([btn_Copy, pu_Sr, pu_Find, pu_Hawb, pu_Freight, pu_AmsEdi, pu_PlSheet, pu_Manifest, pu_Dimens, pu_Print, pu_departmentChange]);
			break;

		case "CREATE": //신규
			$c.gus.cfEnableKeyData();
			scwin.f_EnablePopUpObj();
			$c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete]);
			$c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);

			//Default Setting
			scwin.f_DefaultValue("Create");
			scwin.freightYn = "";
			break;

		case "UPDATE":
			$c.gus.cfDisableBtnOnly([btn_Update, btn_Create]);
			$c.gus.cfEnableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
			$c.gus.cfEnableBtnOnly([btn_Copy, pu_Sr, pu_Find, pu_Hawb, pu_Freight, pu_AmsEdi, pu_PlSheet, pu_Manifest, pu_Dimens, pu_Print, pu_departmentChange]);
			$c.gus.cfDisableKey();
			scwin.f_EnablePopUpObj();
			break;

		case "SAVE":
			$c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
			$c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete]);
			scwin.f_Set("RETRIEVE");
			break;

		case "DELETE":
			$c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
			$c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete]);
			scwin.f_Set("RETRIEVE");
			break;
	}

	//$c.gus.cfDisableObjects([chb_endgb]);
	$c.gus.cfDisableObjects([ed_lecd, txt_lenm, lc_lrgb, img_lecd]); //Master Agent 마스터 부킹에서 수정 해야 됨
	if (scwin.freightYn == "-1") { //운임이 발생 됨
		$c.gus.cfDisableObjects([ed_dept , txt_deptnm, img_dept, ed_itcd, txt_itnm, img_itcd]); //운임 발행시 Item, Department Disable
	}
};


