//-------------------------------------------------------------------------
// 화면이동
//-------------------------------------------------------------------------
scwin._getCommonParam = function () {
	return {
		iogb: $c.str.trim(scwin.hd_iogb),
		blno: $c.str.trim(ed_blno.getValue()),
		mhno: $c.str.trim(lc_mmhno.getValue()),
		kcomcd: $c.str.trim(scwin.hd_kcomcd),
		srno: $c.str.trim(ed_srno.getValue())
	};
};

scwin._openMenu = function (title, path, menuId, param) {
	$c.win.openMenu(title, path, menuId, param || {});
};

scwin.f_openPgm_freight = function () {
	var commonParam = scwin._getCommonParam();
    params = {
        blno: commonParam.blno,
        kcomcd: commonParam.kcomcd,
        mhno: commonParam.mhno
    }
    menuInfo = {
        pgmNm: "Export Master B/L Freight"
    }
    $c.win.openMenu("Master Air Waybill Freight", "/ui/il/airout/aobl/ar_103_01_04b.xml", "ar_103_01_04b.xml", params, menuInfo);
};

scwin.f_openPgm = function (name) {
	var commonParam = scwin._getCommonParam();

	switch (name) {
		case "Freight":
			scwin.f_openPgm_freight();
			break;

		case "AMS":
			scwin._openMenu(
				// "Master Air Waybill AMS EDI",
				"수출 AMS 신고",
				"/ui/il/aredi/aram/ed_112_01_01b.xml",
				"ed_112_01_01b.xml",
				{ kcomcd: commonParam.kcomcd, blno: commonParam.blno, mhno: commonParam.mhno }
			);
			break;

		case "Find":
			scwin._openMenu(
				"Master B/L Search",
				"/ui/il/airout/aobl/ar_103_01_02b.xml",
				"ar_103_01_02b.xml",
				{ iogb: "O" }
			);
			break;

		case "Hawb": //결함2
			scwin._openMenu(
				"Export House B/L",
				"/ui/il/airout/aobl/ar_104_01_01b.xml",
				"ar_104_01_01b.xml",
				{ kcomcd: commonParam.kcomcd, mblno: commonParam.blno, type: "HawbCreate" }
			);
			break;

		case "DIM":
			scwin._openMenu(
				"Master Dimension 1",
				"/ui/il/airout/aobl/ar_103_01_03b.xml",
				"ar_103_01_03b.xml",
				{ kcomcd: commonParam.kcomcd, blno: commonParam.blno, mhno: commonParam.mhno }
			);
			break;

		case "MNF":
			scwin._openMenu(
				"Cargo Manifest",
				"/ui/il/airout/aoth/ar_105_01_01b.xml",
				"ar_105_01_01b.xml",
				{ kcomcd: commonParam.kcomcd, blno: commonParam.blno, mhno: commonParam.mhno }
			);
			break;

		case "PL":
			scwin._openMenu(
				"Booking Sheet",
				"/ui/il/pfm/pfbs/pe_101_01_01b.xml",
				"pe_101_01_01b.xml",
				{
					kcomcd: commonParam.kcomcd,
					seaair: "A",  // sea:S,air:A
					iogb: commonParam.iogb,  // out:O,in:I
					blno: "",  // house blno
					mblno: commonParam.blno,  // master blno
					mhno: commonParam.mhno   // mhno
				}
			);
			break;

		case "Booking":
			scwin._openMenu(
				"Export Customer Booking",
				"/ui/il/airout/aobk/ar_101_01_01b.xml",
				"ar_101_01_01b.xml",
				{ kcomcd: commonParam.kcomcd, srno: commonParam.srno }
			);
			break;

		case "Print":
			scwin._openMenu(
				"Master B/L Print",
				"/ui/il/airout/aobl/ar_103_01_05b.xml",
				"ar_103_01_05b.xml",
				{ kcomcd: commonParam.kcomcd, blno: commonParam.blno, mhno: commonParam.mhno }
			);
			break;

		default:
			break;
	}
}

//-------------------------------------------------------------------------
//  Booking List Binding
//  Booking 정보에 있는 내용을 Master 기본 정보로 보여 준다.
//-------------------------------------------------------------------------
scwin.f_BookingListBinding = function (gubun, dsBooking, dsMaster) {
    var rowBooking = dsBooking.getRowPosition() || 0;
    var rowMaster = dsMaster.getRowPosition() || 0;

	switch (gubun) {
		case "Retrieve":
			dsMaster.setCellData(rowMaster, "mhno", dsBooking.getCellData(rowBooking, "mhno"));
			dsMaster.setCellData(rowMaster, "mblgb", dsBooking.getCellData(rowBooking, "mblgb"));
			dsMaster.setCellData(rowMaster, "ondt", dsBooking.getCellData(rowBooking, "ondt"));
			dsMaster.setCellData(rowMaster, "cjdt", dsBooking.getCellData(rowBooking, "ondt"));
			dsMaster.setCellData(rowMaster, "ontm", dsBooking.getCellData(rowBooking, "ontime"));
			dsMaster.setCellData(rowMaster, "cacd", dsBooking.getCellData(rowBooking, "cacd")); //check
			dsMaster.setCellData(rowMaster, "canm", dsBooking.getCellData(rowBooking, "canm"));
			dsMaster.setCellData(rowMaster, "fltno", dsBooking.getCellData(rowBooking, "fltno"));
			dsMaster.setCellData(rowMaster, "ptcd1", dsBooking.getCellData(rowBooking, "fltno").substring(0, 2));
			dsMaster.setCellData(rowMaster, "cocd", dsBooking.getCellData(rowBooking, "cocd"));
			dsMaster.setCellData(rowMaster, "conm", dsBooking.getCellData(rowBooking, "conm"));
			dsMaster.setCellData(rowMaster, "dpcd", dsBooking.getCellData(rowBooking, "dpcd"));
			dsMaster.setCellData(rowMaster, "dstn", dsBooking.getCellData(rowBooking, "dscd"));
			dsMaster.setCellData(rowMaster, "dpnm", dsBooking.getCellData(rowBooking, "dpnm"));
			dsMaster.setCellData(rowMaster, "dscd1", dsBooking.getCellData(rowBooking, "dscd"));
			dsMaster.setCellData(rowMaster, "dsnm1", dsBooking.getCellData(rowBooking, "dsnm"));
			dsMaster.setCellData(rowMaster, "warecd", dsBooking.getCellData(rowBooking, "warecd"));
			dsMaster.setCellData(rowMaster, "warenm", dsBooking.getCellData(rowBooking, "warenm"));
			dsMaster.setCellData(rowMaster, "bltype", dsBooking.getCellData(rowBooking, "bltype"));
			dsMaster.setCellData(rowMaster, "shipgb", dsBooking.getCellData(rowBooking, "shipgb"));
			dsMaster.setCellData(rowMaster, "mftpkg", dsBooking.getCellData(rowBooking, "ctn"));
			dsMaster.setCellData(rowMaster, "mftwht", dsBooking.getCellData(rowBooking, "gwht"));
			dsMaster.setCellData(rowMaster, "avdt", dsBooking.getCellData(rowBooking, "avdt"));
			dsMaster.setCellData(rowMaster, "avtm", dsBooking.getCellData(rowBooking, "avtime"));
			dsMaster.setCellData(rowMaster, "voidgb", dsBooking.getCellData(rowBooking, "voidgb"));
			dsMaster.setCellData(rowMaster, "lecd", dsBooking.getCellData(rowBooking, "lecd"));
			dsMaster.setCellData(rowMaster, "lenm", dsBooking.getCellData(rowBooking, "lenm"));

			//scwin.f_AirportDestination();
			scwin.f_DestinationCheck(); // 국가 코드 뿌려 주기 위해

			if (ed_ctcd.getValue().length > 0) {
				scwin.f_OpenCommonPopUp("Country", "T", "F", "F");
			}

			break;

		case "Copy":
			dsMaster.setCellData(rowMaster, "mhno", dsBooking.getCellData(rowBooking, "mhno"));
			dsMaster.setCellData(rowMaster, "mblgb", dsBooking.getCellData(rowBooking, "mblgb"));
			dsMaster.setCellData(rowMaster, "ondt", dsBooking.getCellData(rowBooking, "ondt"));
			dsMaster.setCellData(rowMaster, "avdt", dsBooking.getCellData(rowBooking, "avdt"));
			dsMaster.setCellData(rowMaster, "cacd", dsBooking.getCellData(rowBooking, "cacd"));
			dsMaster.setCellData(rowMaster, "canm", dsBooking.getCellData(rowBooking, "canm"));
			dsMaster.setCellData(rowMaster, "bltype", dsBooking.getCellData(rowBooking, "bltype"));
			dsMaster.setCellData(rowMaster, "shipgb", dsBooking.getCellData(rowBooking, "shipgb"));

			break;

		default:
			break;
	}

    scwin._syncHiddenFromDs();
}

//-------------------------------------------------------------------------
//Other Type Setting
//-------------------------------------------------------------------------
scwin.f_OtherTypeSetting = function () {
	var otpc_value = "";
	if (chb_otpc1.checked) {
		otpc_value = "PP";
	}
	if (chb_otpc2.checked) {
		otpc_value = "CC";
	}
	if ((chb_otpc1.checked) && (chb_otpc2.checked)) {
		otpc_value = "PC";
	}

    ds_MasterBillInfo.setRowPosition(0);
	ds_MasterBillInfo.setCellData(ds_MasterBillInfo.getRowPosition(), "otpc", otpc_value);
}

//-------------------------------------------------------------------------
//Other Type Getting
//-------------------------------------------------------------------------
scwin.f_OtherTypeGetting = function () {
	chb_otpc1.setValue("0");
	chb_otpc2.setValue("0");

	if (scwin.hd_otpc == "PP") {
		chb_otpc1.setValue("1");
	}
	if (scwin.hd_otpc == "CC") {
		chb_otpc2.setValue("1");
	}
	if (scwin.hd_otpc == "PC") {
		chb_otpc1.setValue("1");
		chb_otpc2.setValue("1");
	}
}

//-------------------------------------------------------------------------
//Other Type Getting
//-------------------------------------------------------------------------
scwin.f_TypeInfoSetting = function (gubun, ds) {
    ds.setRowPosition(0);

	switch (gubun) {
		case "MasterInfo":
			ed_mblgb.setValue(ds.getCellData(ds.getRowPosition(), "mblgbDesc"));
			ed_shipgb.setValue(ds.getCellData(ds.getRowPosition(), "shipgbDesc"));
			break;

		case "BookingInfo":
			ed_mblgb.setValue(ds.getCellData(ds.getRowPosition(), "mblgbDesc"));
			ed_shipgb.setValue(ds.getCellData(ds.getRowPosition(), "shipgbDesc"));
			break;

		default:
			ed_mblgb.setValue("");
			ed_shipgb.setValue("");
			break;
	}

}

//-------------------------------------------------------------------------
// ilpopupdefine 열기 (팝업)
//-------------------------------------------------------------------------
scwin.f_PopUp = async function(disGubun, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    switch (disGubun){

        //Booking No
        case "CustomerBookingInfo" :		
            if (ed_shipgb.getValue() != "Direct") {
                break;
            }

            if (ed_srno.getValue() == "") {
                udc_bookingNo.ilCommonPopUp(scwin.udc_bookingNo_callBackFun,    		// XML상의 SELECT ID	                                                   							
                                        ed_ondt.getValue(),                             // 화면에서의 ??? Code Element의	Value                                  
                                        '',                             // 화면에서의 ??? Name Element의	Value                                  
                                        pWinCloseTF,                    // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                        '4',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                        "Booking No, Onboard, Shipper,Remark,''",           // Title순서	 										                                                       
                                        '100,80,200,250',				    // 보여주는 각 컬럼들의 폭	
                                        "5,6,7,8,9,10",	                        // 컬럼중에서 숨기는	컬럼 지정	                                    
                                        null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                        '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                        '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                        null,                           // 윈도우 위치 Y좌표	                                                   
                                        null,                           // 윈도우 위치 X좌표                                                       
                                        null,                           // 중복체크여부	("F")                                                      
                                        pAllSearchTF,                   // 전체검색허용여부	("F")                                                  
                                        "Booking No, Onboard, Shipper",                            // POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
                                        pNoDataCloseTF);
            }
            break;		

        // Shipper
        case "Shipper" :		//거래처 팝업(Search Shipper)
            udc_shcd.ilCommonPopUp(scwin.udc_shcd_callBackFun,    		// XML상의 SELECT ID	                                                   							
                                    ed_shcd.getValue(),            // 화면에서의 ??? Code Element의	Value                                  
                                    scwin.txt_shnm1,                // 화면에서의 ??? Name Element의	Value                                  
                                    pWinCloseTF,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                    '6',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    'Shipper',                      // Title순서	                                                           
                                    '140,300',                      // 보여주는 각 컬럼들의 폭	                                               
                                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                                    null,                           // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                    null,                           // 윈도우 위치 Y좌표	                                                   
                                    null,                           // 윈도우 위치 X좌표                                                       
                                    null,                           // 중복체크여부	("F")                                                      
                                    pAllSearchTF,                   // 전체검색허용여부	("F")                                                  
                                    null, 							// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  
                                    pNoDataCloseTF);               
            break;												

        // Consignee
        case "Consignee" :
            udc_cncd.ilCommonPopUp(scwin.udc_cncd_callBackFun,
                                    ed_cncd.getValue(),  
                                    scwin.txt_cnnm1, 
                                    pWinCloseTF,
                                    '6',
                                    'Consignee', '140,300',
                                    null, null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;			

        // Notify
        case "Notify" :
            udc_ntcd.ilCommonPopUp(scwin.udc_ntcd_callBackFun,
                                    ed_ntcd.getValue(),  
                                    scwin.txt_ntnm1, 
                                    pWinCloseTF,
                                    '6',
                                    'Notify', '140,300',
                                    null, null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;			

        // Carrier
        case "Carrier" :
            udc_cacd.ilCommonPopUp(scwin.udc_cacd_callBackFun,
                                    ed_cacd.getValue(),  
                                    txt_canm.getValue(), 
                                    pWinCloseTF,
                                    '2',
                                    'Carrier', '140,300', 
                                    "3,4,5,6,7,8,9,10", 
                                    null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;

        // Master Agent
        case "MasterAgt" :
            udc_lecd.ilCommonPopUp(scwin.udc_lecd_callBackFun,
                                    ed_lecd.getValue(),  
                                    txt_lenm.getValue(), 
                                    pWinCloseTF,
                                    '2',
                                    'Agent', '140,300', 
                                    "3,4,5,6,7,8,9,10", 
                                    null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;

        // Departure
        case "Departure" :
            udc_dpcd.ilCommonPopUp(scwin.udc_dpcd_callBackFun,
                                    ed_dpcd.getValue(),  
                                    txt_dpnm.getValue(), 
                                    pWinCloseTF,
                                    '2',
                                    'Port Code, Port Name', 
                                    '140,300', 
                                    "3,4,5,6,7,8,9,10", 
                                    null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    'Departure Search, Port Code, Port Name',
                                    pNoDataCloseTF);
            break;

        // Customer
        case "Customer" :
            udc_ascd.ilCommonPopUp(scwin.udc_ascd_callBackFun,
                                    ed_ascd.getValue(),  
                                    txt_asnm.getValue(), 
                                    pWinCloseTF,
                                    '2',
                                    'Customer', 
                                    '140,300', 
                                    "3,4,5,6,7,8,9,10", 
                                    null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;

        // PIC
        case "CustomerPic":
            let pParam = ed_ascd.getValue();
            udc_ascdpic.ilCommonPopUp(scwin.udc_ascdpic_callBackFun,			// XML상의 SELECT ID	                                                   
                                    ed_ascdpic.getValue(),            // 화면에서의 ??? Code Element의	Value                                  
                                    txt_ascdpicnm.getValue(),                 // 화면에서의 ??? Name Element의	Value                                  
                                    pWinCloseTF,                       // 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)         
                                    '4',                            // 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    "Customer PIC", 		                	// Title순서	                                                           
                                    //'80,200,120,300',               // 보여주는 각 컬럼들의 폭	                                               
                                    '100,350',               // 보여주는 각 컬럼들의 폭	                                               
                                    null,                           // 컬럼중에서 숨기는	컬럼 지정	                                       
                                    pParam,                         // SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능              
                                    '500',                          // POP-UP뛰을때 원도우의	사용자 정의	폭                                 
                                    '500',                          // POP-UP뛰을때 우도우의	사용자 정의	높이	                           
                                    null,                           // 윈도우 위치 Y좌표	                                                   
                                    null,                           // 윈도우 위치 X좌표                                                       
                                    null,                           // 중복체크여부	("F")                                                      
                                    "T",                            // 전체검색허용여부	("F")                                                  
                                    null);							// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")  			
            break;		

        // Currency
        case "Currency" :		//Search Currency
            udc_cucd.ilCommonPopUp(scwin.udc_cucd_callBackFun,
                                    ed_cucd.getValue(),  
                                    ed_cucd.getValue(), 
                                    pWinCloseTF,
                                    '2',
                                    'Currency', 
                                    '140,300', 
                                    "3,4,5,6,7,8,9,10", 
                                    null,
                                    '500', '500',
                                    null, null, null,
                                    pAllSearchTF,
                                    null,
                                    pNoDataCloseTF);
            break;				

        default:
            break;
    }
};

