scwin.sbm_Save_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Code < 0) return;	// OnFail

	if (scwin.actionFlag == "Save") {
		await $c.gus.cfAlertMsg(E_MSG_CM_INF_001);	// 성공적으로 저장하였습니다
		scwin.f_MhnoLoading();  // 저장 후 MHNO 검색
		await scwin.f_Retrieve();
	}

	if (scwin.actionFlag == "Delete") {
		await $c.gus.cfAlertMsg(E_MSG_CM_INF_004);	// 성공적으로 삭제하였습니다
		scwin.f_Set("DELETE");

		//삭제 후 Setting 작업
		ds_HouseBillInfo.removeAll();
        totalRow.setValue(ds_HouseBillInfo.getTotalRow());

		scwin.f_TypeInfoSetting("Delete");
		ed_blno.setValue("");
		lc_mmhno.setValue("");
		ta_hhs.setValue("");
		ta_hhn.setValue("");
		ta_hhc.setValue("");
		ed_blno.focus();
	}
};

